#include <stdio.h>
#include <string.h>
#define MAX 200000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[MAX];
        scanf("%s", S);
        int Q;
        scanf("%d", &Q);
        int len = strlen(S);
        int freq[MAX][MAX] = {{0}};
        for (int i = 0; i < len; i++) {
            for (int j = i; j < len; j++) {
                char substr[j - i + 1 + 1];
                strncpy(substr, S + i, j - i + 1);
                substr[j - i + 1] = '\0';
                int hash = 0;
                for (int k = 0; k < strlen(substr); k++) {
                    hash += substr[k];
                }
                freq[i][j] = 1;
                for (int k = 0; k < len; k++) {
                    for (int l = k; l < len; l++) {
                        char substr2[l - k + 1 + 1];
                        strncpy(substr2, S + k, l - k + 1);
                        substr2[l - k + 1] = '\0';
                        int hash2 = 0;
                        for (int m = 0; m < strlen(substr2); m++) {
                            hash2 += substr2[m];
                        }
                        if (hash == hash2 && strcmp(substr, substr2) == 0) {
                            freq[i][j]++;
                        }
                    }
                }
            }
        }
        while (Q--) {
            int Fi;
            scanf("%d", &Fi);
            int count = 0;
            for (int i = 0; i < len; i++) {
                for (int j = i; j < len; j++) {
                    if (freq[i][j] >= Fi) {
                        count++;
                    }
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
#include <unordered_map>
using namespace std;
int main() {
    int T;
    cin >> T;
    while (T--) {
        string S;
        cin >> S;
        int Q;
        cin >> Q;
        int len = S.length();
        unordered_map<string, int> freq;
        for (int i = 0; i < len; i++) {
            for (int j = i; j < len; j++) {
                string substr = S.substr(i, j - i + 1);
                if (freq.find(substr) != freq.end()) {
                    freq[substr]++;
                } else {
                    freq[substr] = 1;
                }
            }
        }
        while (Q--) {
            int Fi;
            cin >> Fi;
            int count = 0;
            for (auto& it : freq) {
                if (it.second >= Fi) {
                    count++;
                }
            }
            cout << count << endl;
        }
    }
    return 0;
}

